import React from "react";

const BarraHorizontal = ({
  texto,
  height = "15vh",
  margenHorizontal = "10vw",
  imagen,
}) => {
  const containerStyle = {
    width: "100%",
    height,
    display: "flex",
    alignItems: "center",
    overflow: "hidden",
  };

  const imagenStyle = {
    backgroundImage: `url(${imagen})`,
    backgroundRepeat: "repeat-x",
    backgroundPosition: "center",
    backgroundSize: "auto 100%",
    height: "100%",
    width: margenHorizontal,
    flexShrink: 0,
    margin: 0,  // Sin separación
    padding: 0,
  };

  const textoStyle = {
    flexGrow: 1,
    height: "100%",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontSize: "calc(0.5rem + 1vw)",
    fontWeight: "bold",
    fontFamily: "sans-serif", // o alguna que no tenga tanto padding interno
    margin: 0,
    padding: 0,
    lineHeight: "normal",
    transform: "translateY(-2%)", // Ajuste fino
  };
  

  return (
    <div style={containerStyle}>
      <div style={imagenStyle} />
      <div style={textoStyle}>{texto}</div>
      <div style={imagenStyle} />
    </div>
  );
};

export default BarraHorizontal;
